import React, { useContext, useState, useEffect } from "react";
import {
  View,
  Text,
  StyleSheet,
  Pressable,
  Image,
  ScrollView,
  ActivityIndicator,
} from "react-native";
import * as ImagePicker from "expo-image-picker";
import * as DocumentPicker from "expo-document-picker";
import { AppContext } from "../../../App";
import { uploadVerificationDocument } from "../../api/verificationApi";
import { useFormNavigation } from "../../utils/navigationUtils";
import Header from "../../components/Header";
import { useTranslation } from "../../i18n"; // Import translation hook

const COLORS = {
  primary: "#7C3AED",
  background: "#F7F9FA",
  card: "#FFFFFF",
  textDark: "#1C1C1E",
  textMuted: "#6B7280",
  error: "#DC2626",
  border: "#E5E7EB",
};

function CheckRow({ label, checked, onPress }) {
  return (
    <Pressable onPress={onPress} style={styles.checkRow}>
      <View style={[styles.checkBox, checked && styles.checkBoxOn]}>
        {checked ? <Text style={styles.checkMark}>✓</Text> : null}
      </View>
      <Text style={styles.checkLabel}>{label}</Text>
    </Pressable>
  );
}

const PublicTransportDocumentUploadScreen = ({ navigation }) => {
  const { verification, setVerification, setFormProgress } =
    useContext(AppContext);
  const { goToNextStep, updateCurrentStep } = useFormNavigation();
  const { t } = useTranslation(); // Initialize translation hook

  const [files, setFiles] = useState([]);
  const [uploading, setUploading] = useState(false);
  const [error, setError] = useState(null);
  const [skip, setSkip] = useState(false);

  useEffect(() => {
    updateCurrentStep("public_transport_doc_upload");
  }, []);

  useEffect(() => {
    if (files.length > 0) {
      setVerification((prev) => ({
        ...prev,
        documents: {
          ...prev.documents,
          carteTransport: files,
        },
      }));
    }
  }, [files]);

  const handleCamera = async () => {
    setError(null);
    const perm = await ImagePicker.requestCameraPermissionsAsync();
    if (!perm.granted) {
      setError(t("documentUpload.cameraPermissionDenied"));
      return;
    }

    const result = await ImagePicker.launchCameraAsync({
      mediaTypes: ImagePicker.MediaTypeOptions.Images,
      quality: 0.8,
    });

    if (!result.canceled && result.assets?.[0]) {
      const a = result.assets[0];
      setFiles((prev) => [
        ...prev,
        {
          uri: a.uri,
          name: a.fileName || "carte_transport_photo.jpg",
          mimeType: "image/jpeg",
          type: "image/jpeg",
        },
      ]);
    }
  };

  const handlePickDoc = async () => {
    setError(null);
    const result = await DocumentPicker.getDocumentAsync({
      type: ["application/pdf", "image/*"],
      multiple: true,
    });
    if (result.type === "cancel") return;

    const assets = result.assets || [result];
    const mapped = assets.map((a) => ({
      uri: a.uri,
      name: a.name || "carte_transport_doc",
      mimeType: a.mimeType || "application/octet-stream",
      type: a.mimeType || "application/octet-stream",
    }));

    setFiles((prev) => [...prev, ...mapped]);
  };

  const handleRemove = (idx) =>
    setFiles((prev) => prev.filter((_, i) => i !== idx));

  const handleNext = async () => {
    if (!verification.verificationId) {
      setError(t("documentUpload.noVerificationFound"));
      return;
    }

    // ✅ Skip: allow continuing without upload and without backend calls
    if (skip) {
      setFormProgress((prev) => ({
        ...prev,
        completedSteps: [
          ...new Set([...prev.completedSteps, "public_transport_doc_upload"]),
        ],
        currentStep: "tax_payment_receipt_doc_upload",
      }));

      setVerification((prev) => ({
        ...prev,
        documents: {
          ...(prev?.documents || {}),
          carteTransport: [],
          publicTransportSkipped: true,
        },
      }));

      goToNextStep("tax_payment_receipt_doc_upload");
      return;
    }

    if (files.length === 0) {
      setError(t("documentUpload.addAtLeastOne"));
      return;
    }

    try {
      setUploading(true);
      setError(null);

      for (const f of files) {
        await uploadVerificationDocument(
          verification.verificationId,
          "CARTE_TRANSPORT",
          f
        );
      }

      setFormProgress((prev) => ({
        ...prev,
        completedSteps: [
          ...new Set([...prev.completedSteps, "public_transport_doc_upload"]),
        ],
        currentStep: "tax_payment_receipt_doc_upload",
      }));

      goToNextStep("tax_payment_receipt_doc_upload");
    } catch (e) {
      console.log("Error uploading carte transport:", e);
      setError(t("documentUpload.transportUploadError"));
    } finally {
      setUploading(false);
    }
  };

  return (
    <View style={styles.screen}>
      <Header />
      {/* Back button */}

      <ScrollView contentContainerStyle={styles.scroll}>
        <Pressable
          style={styles.backButton}
          onPress={() => navigation.navigate("car_registration_doc_upload")}
        >
          <Text style={styles.backIcon}>←</Text>
        </Pressable>
        <Text style={styles.title}>{t("documentUpload.transportTitle")}</Text>
        <Text style={styles.subtitle}>
          {t("documentUpload.transportSubtitle")}
        </Text>

        <View style={styles.card}>
          <Pressable style={styles.uploadOption} onPress={handleCamera}>
            <Image
              source={require("../../../assets/camera.png")}
              style={styles.icon}
            />
            <View>
              <Text style={styles.optionTitle}>{t("documentUpload.takePhoto")}</Text>
              <Text style={styles.optionHint}>
                {t("documentUpload.transportPhotoHint")}
              </Text>
            </View>
          </Pressable>

          <Pressable style={styles.uploadOption} onPress={handlePickDoc}>
            <Image
              source={require("../../../assets/file_upload.png")}
              style={styles.icon}
            />
            <View>
              <Text style={styles.optionTitle}>{t("documentUpload.importFile")}</Text>
              <Text style={styles.optionHint}>{t("documentUpload.fileFormats")}</Text>
            </View>
          </Pressable>
        </View>

        {files.map((f, idx) => (
          <View key={idx} style={styles.fileRow}>
            <Text style={styles.fileName}>{f.name}</Text>
            <Pressable onPress={() => handleRemove(idx)}>
              <Text style={styles.remove}>{t("documentUpload.remove")}</Text>
            </Pressable>
          </View>
        ))}

        {error && <Text style={styles.error}>{error}</Text>}

        {/* ✅ Skip checkbox */}
        <Pressable
          onPress={() => setSkip((v) => !v)}
          style={({ pressed }) => [
            styles.skipRow,
            pressed && { opacity: 0.85 },
          ]}
        >
          <View style={[styles.skipBox, skip && styles.skipBoxOn]}>
            {skip ? <Text style={styles.skipMark}>✓</Text> : null}
          </View>
          <Text style={styles.skipLabel}>{t("documentUpload.skip")}</Text>
        </Pressable>

        <Pressable
          onPress={handleNext}
          disabled={(!skip && files.length === 0) || uploading}
          style={[
            styles.cta,
            ((!skip && files.length === 0) || uploading) && { opacity: 0.5 },
          ]}
        >
          {uploading ? (
            <ActivityIndicator color="#FFF" />
          ) : (
            <Text style={styles.ctaText}>{t("documentUpload.next")}</Text>
          )}
        </Pressable>
      </ScrollView>
    </View>
  );
};

